<?php
namespace App\Http\Controllers;
use App\Models\{Category,Product};use Illuminate\Http\Request;use Illuminate\View\View;
class ProductController extends Controller{public function index(Request $request):View{$query=Product::with('category')->where('is_active',1);$query->when($request->q,fn($q,$v)=>$q->where(fn($s)=>$s->where('name','like',"%$v%")->orWhere('brand','like',"%$v%")));$query->when($request->category,fn($q,$v)=>$q->whereHas('category',fn($c)=>$c->where('slug',$v)));$query->when($request->brand,fn($q,$v)=>$q->where('brand',$v));$query->when($request->min_price,fn($q,$v)=>$q->where('price','>=',$v));$query->when($request->max_price,fn($q,$v)=>$q->where('price','<=',$v));match($request->sort){'cheap'=>$query->orderBy('discount_price')->orderBy('price'),'expensive'=>$query->orderByDesc('discount_price')->orderByDesc('price'),'popular'=>$query->orderByDesc('sales_count'),default=>$query->latest()};return view('products.index',['products'=>$query->paginate(12)->withQueryString(),'categories'=>Category::where('is_active',1)->get(),'brands'=>Product::where('is_active',1)->whereNotNull('brand')->distinct()->pluck('brand')]);}public function show(string $slug):View{$product=Product::with('category')->where('slug',$slug)->where('is_active',1)->firstOrFail();$related=Product::where('is_active',1)->where('category_id',$product->category_id)->whereKeyNot($product->id)->take(4)->get();return view('products.show',compact('product','related'));}}
